<?php//	define('MICROLOAD', true);	// Загружаем файл конфига, ВАЖНЫЙ.	include ($_SERVER['DOCUMENT_ROOT'].'/configs/config.php');	// Подключаемся к SQL базе	$db = new MySQL(SQL_USER, SQL_PASS, SQL_BASE);	// Подключаем класс обработки входящих данных	$http = new Jhttp();	############################## 		$pers = $db->sqla('SELECT * FROM `users` WHERE `uid`="'.abs(intval($_COOKIE['uid'])).'" and `pass`="'.addslashes($_COOKIE['hashcode']).'" and `block`="" LIMIT 1;');//	if ($pers == false) die('Вы не авторизированы в игре!');		$print = '';		function send_mail($to, $body, $title=false)	{		$email = 'robot@'.$_SERVER['HTTP_HOST'];		$subject = ($title==false) ? $_SERVER['SERVER_NAME'] : htmlspecialchars($title);		$headers = "From: ".$_SERVER['SERVER_NAME']." <".$email.">\r\n";   		$headers .= "Return-path: <".$email.">\r\n";		$headers .= "MIME-Version: 1.0\r\n";		$headers .= "Content-type: text/html; charset=windows-1251;\r\n";		$body.= '<br /><br />С Уважением, Администрация <a href=http://'.$_SERVER['HTTP_HOST'].'/>'.$_SERVER['SERVER_NAME'].'</a> &copy;';		if( mail($to, $subject, $body, $headers) ) return true; else return false;	}		if ( isset($http->get['do']) )	{		if ($http->get['do']=='mailgo' and $pers==true and $pers['mail_good']==0)		{			$hesh = sha1(tme().rand(0, tme()));			$db->sql('INSERT INTO `mail_hesh` (`uid`, `hesh`, `date`) VALUES ('.$pers['uid'].', "'.$hesh.'", '.tme().');');			$db->sql('UPDATE `users` SET `mail_good`=2 WHERE `uid`='.$pers['uid']);			$linc = 'http://'.$_SERVER['HTTP_HOST'].'/mail.php?do=check&hesh='.$hesh;			send_mail($pers['email'], 'Для подтверждения Вашего E-Mail перейдите по ссылке <a href="'.$linc.'">'.$linc.'</a>', 'Подтверждение E-Mail');			$pers['mail_good'] = 2;		} elseif ($http->get['do']=='check') {			$hesh = (int)$db->sqlr('SELECT `uid` FROM `mail_hesh` WHERE `hesh`="'.$http->get['hesh'].'" LIMIT 1');			if ( $hesh )			{				$mail = $db->sqlr('SELECT `email` FROM `users` WHERE `uid`='.$hesh);				$db->sql('DELETE FROM `mail_hesh` WHERE `uid` = '.$hesh);				$db->sql('UPDATE `users` SET `mail_good`=1 WHERE `uid`='.$hesh);				$db->sql('INSERT INTO `watch_passmail` (`uid`, `date`, `type`, `text`, `ip`) VALUES ('.$hesh.', '.tme().', 1, "'.$mail.'", "'.$http->is_ip().'");');				$print = 'Ваш E-Mail успешно подтвержден!';				unset($_GET);			} else $print = 'Неверный проверочный код! Если возникли проблемы, обратитесь к Администрации проекта.';				}			}?><html><head><meta http-equiv="Content-Language" content="en-us"><LINK href="/css/main_v2.css" rel="STYLESHEET" type="text/css"><title>E-Mail Сервис</title><meta http-equiv="content-type" content="text/html; charset=windows-1251"></head><body><center style="top:40%; position:absolute; width:100%"><div style="width:500px" class=but>Свойства E-mail<div style="width:90%" class=but2><?phpif ( !empty($print) ) echo $print;elseif ($pers==true and $pers['mail_good']==1) echo 'Ваш E-Mail адрес уже подтвержден!';elseif ($pers==true and $pers['mail_good']==2) echo 'На Ваш E-Mail «'.$pers['email'].'» было отправлено письмо с ссылкой для подтверждения правельности почты, если вы не получили письмо, вы можете изменив e-mail в разделе О Вас, это вызовет отправку подтверждения повторно!';elseif ($pers==true and $pers['mail_good']==0) echo 'Ваш E-Mail не подтвержден! Отправить на него ссылку для подтверждения? <a href="?do=mailgo">Отправить</a>';else echo 'Ошибка!';?></div>*Администрация не рекомендует использовать бесплатные сервисы почты, такие как mail.ru, rembler.ru, yandex.ru, так как получение писем может быть невозможным. Рекомендуется использование сервиса gmail.com</div></center></body></html>